// constructive algorithms, greedy, dp
class Solution {
public:
    string findTheString(vector<vector<int>>& lcp) {
        string result(size(lcp), 0);
        for (int i = 0, curr = 'a'; i < size(lcp); ++i) {
            if (result[i]) {
                continue;
            }
            if (curr > 'z') {
                return "";
            }
            for (int j = i; j < size(lcp[0]); ++j) {
                if (lcp[i][j]) {
                    result[j] = curr;
                }
            }
            ++curr;
        }
        for (int i = size(lcp) - 1; i >= 0; --i) {
            for (int j = size(lcp[0]) - 1; j >= 0; --j) {
                if (lcp[i][j] != (result[i] == result[j] ? (i + 1 < size(lcp) && j + 1 < size(lcp[0]) ? lcp[i + 1][j + 1] + 1: 1): 0)) {
                    return "";
                }
            }
        }
        return result;
    }
};

# Time:  O(n^2)
# Space: O(1)

# constructive algorithms, greedy, dp
class Solution(object):
    def findTheString(self, lcp):
        """
        :type lcp: List[List[int]]
        :rtype: str
        """
        result = [-1]*len(lcp)
        curr = 0
        for i in xrange(len(lcp)):
            if result[i] != -1:
                continue
            if curr == 26:
                return ""
            for j in xrange(i, len(lcp[0])):
                if lcp[i][j]:
                    result[j] = curr
            curr += 1
        for i in reversed(xrange(len(lcp))):
            for j in reversed(xrange(len(lcp[0]))):
                if lcp[i][j] != ((lcp[i+1][j+1]+1 if i+1 < len(lcp) and j+1 < len(lcp[0]) else 1) if result[i] == result[j] else 0):
                    return ''
        return "".join(map(lambda x: chr(ord('a')+x), result))
